// Icons keyed by colour (as returned by alertColourLevel), plus "statement" for no-colour alerts
const ALERT_ICONS = {
  "red": "data:image/svg+xml;base64,",
  "orange": "data:image/svg+xml;base64,",
  "yellow": "data:image/svg+xml;base64,",
  "statement": "data:image/svg+xml;base64,",
};

/**
 * Environment Canada Weather Card for Home Assistant
 *
 * Uses a weather entity for forecast data but overrides the current
 * condition text and icon using separate Environment Canada sensors.
 *
 * Install via HACS: https://github.com/michaeldavie/environment-canada-weather-card
 */

class EnvironmentCanadaWeatherCard extends HTMLElement {
  static getConfigElement() {
    return document.createElement("environment-canada-weather-card-editor");
  }

  static getStubConfig(hass) {
    const weatherEntities = hass ? Object.keys(hass.states).filter(e => e.startsWith("weather.")) : [];
    const entity = weatherEntities.find(e => e.includes("forecast")) || weatherEntities[0] || "weather.home_forecast";
    return { weather_entity: entity };
  }

  constructor() {
    super();
    this._forecast = [];
    this._forecastSubscription = null;
    this._subscribing = false;
    this._updateTimeout = null;
  }

  set hass(hass) {
    const oldHass = this._hass;
    this._hass = hass;

    if (!this._config) {
      return;
    }

    // Subscribe to forecast if not already subscribed (and not currently subscribing)
    if (hass && hass.connection && !this._forecastSubscription && !this._subscribing) {
      this._subscribeForecast();
    }

    // Debounce updates to prevent excessive DOM thrashing
    clearTimeout(this._updateTimeout);
    this._updateTimeout = setTimeout(() => this._updateCard(), 50);
  }

  setConfig(config) {
    if (!config.weather_entity) {
      throw new Error("You must specify a weather_entity");
    }

    // Unsubscribe from old forecast if config changes
    if (this._forecastSubscription) {
      this._forecastSubscription();
      this._forecastSubscription = null;
    }

    const station = _stationFromWeatherEntity(config.weather_entity);

    this._config = {
      show_forecast: true,
      forecast_type: "daily",
      name: "",
      condition_sensor: `sensor.${station}_current_condition`,
      icon_code_sensor: `sensor.${station}_icon_code`,
      wind_chill_sensor: `sensor.${station}_wind_chill`,
      humidex_sensor: `sensor.${station}_humidex`,
      alerts_sensor: `sensor.${station}_alerts`,
      ...config
    };

    this._forecast = [];
    this._createCard();

    // Re-subscribe with new config
    if (this._hass && this._hass.connection) {
      this._subscribeForecast();
    }
  }

  async _subscribeForecast() {
    // Prevent concurrent subscription attempts (race condition fix)
    if (this._subscribing || this._forecastSubscription) {
      return;
    }

    if (!this._hass || !this._hass.connection || !this._config) {
      return;
    }

    this._subscribing = true;

    try {
      this._forecastSubscription = await this._hass.connection.subscribeMessage(
        (event) => {
          this._forecast = event.forecast || [];
          // Debounce forecast-triggered updates as well
          clearTimeout(this._updateTimeout);
          this._updateTimeout = setTimeout(() => this._updateCard(), 50);
        },
        {
          type: "weather/subscribe_forecast",
          entity_id: this._config.weather_entity,
          forecast_type: this._config.forecast_type
        }
      );
    } catch (e) {
      console.warn("Environment Canada Weather Card: Could not subscribe to forecast", e);
      // Fallback to attribute-based forecast (older HA versions)
      this._forecast = [];
    } finally {
      this._subscribing = false;
    }
  }

  disconnectedCallback() {
    // Clean up subscription
    if (this._forecastSubscription) {
      this._forecastSubscription();
      this._forecastSubscription = null;
    }
    // Clean up pending timeout to prevent updates after disconnect
    clearTimeout(this._updateTimeout);
    this._updateTimeout = null;
  }

  _createCard() {
    if (!this.shadowRoot) {
      this.attachShadow({ mode: "open" });
    }

    this.shadowRoot.innerHTML = `
      <style>
        :host {
          display: block;
        }
        ha-card {
          padding: 16px;
          box-sizing: border-box;
        }
        .header {
          margin-bottom: 16px;
        }
        .alerts-container {
          display: flex;
          flex-direction: column;
          gap: 4px;
          align-items: flex-end;
          margin-left: auto;
          min-width: 0;
        }
        .name {
          font-size: 1.1em;
          font-weight: 500;
          color: var(--primary-text-color);
        }
        .alert {
          display: flex;
          align-items: center;
          gap: 6px;
          min-width: 0;
        }
        .alert-text {
          font-size: 1.1em;
          color: var(--secondary-text-color);
          text-align: right;
          min-width: 0;
          overflow-wrap: break-word;
        }
        .alert-icon {
          width: 28px;
          height: 28px;
          flex-shrink: 0;
        }
        .alert-icon img {
          width: 100%;
          height: 100%;
        }
        .current {
          display: flex;
          align-items: flex-start;
          gap: 16px;
          margin-bottom: 16px;
        }
        .current-icon {
          width: 64px;
          height: 64px;
          flex-shrink: 0;
        }
        .current-icon img {
          width: 100%;
          height: 100%;
          object-fit: contain;
        }
        .current-info {
          flex-grow: 1;
        }
        .current-temp {
          font-size: 2.5em;
          font-weight: 400;
          line-height: 1;
          color: var(--primary-text-color);
        }
        .current-temp .unit {
          font-size: 0.5em;
          vertical-align: super;
          color: var(--secondary-text-color);
        }
        .current-condition {
          font-size: 1em;
          color: var(--secondary-text-color);
          margin-top: 4px;
        }
        .attributes {
          display: flex;
          flex-wrap: wrap;
          gap: 8px 16px;
          margin-bottom: 16px;
          font-size: 0.9em;
          color: var(--secondary-text-color);
        }
        .attribute {
          display: flex;
          align-items: center;
          gap: 4px;
        }
        .attribute ha-icon {
          --mdc-icon-size: 18px;
          color: var(--secondary-text-color);
        }
        .forecast {
          display: flex;
          justify-content: space-between;
          border-top: 1px solid var(--divider-color);
          padding-top: 16px;
        }
        .forecast-day {
          display: flex;
          flex-direction: column;
          align-items: center;
          flex: 1;
          text-align: center;
        }
        .forecast-day .weekday {
          font-size: 0.9em;
          color: var(--secondary-text-color);
          margin-bottom: 4px;
        }
        .forecast-day .icon {
          width: 32px;
          height: 32px;
          margin-bottom: 4px;
        }
        .forecast-day .icon ha-icon {
          --mdc-icon-size: 32px;
          color: var(--secondary-text-color);
        }
        .forecast-day .temp-high {
          font-size: 1em;
          color: var(--primary-text-color);
        }
        .forecast-day .temp-low {
          font-size: 1em;
          color: var(--secondary-text-color);
        }
        .unavailable {
          padding: 16px;
          text-align: center;
          color: var(--secondary-text-color);
        }
      </style>
      <ha-card>
        <div class="content"></div>
      </ha-card>
    `;

    this._content = this.shadowRoot.querySelector(".content");
  }

  _updateCard() {
    if (!this._content || !this._hass || !this._config) {
      return;
    }

    const weather = this._hass.states[this._config.weather_entity];
    const conditionSensor = this._hass.states[this._config.condition_sensor]
      || this._hass.states[this._config.condition_sensor.replace("_current_condition", "_condition")];
    const iconCodeSensor = this._hass.states[this._config.icon_code_sensor];

    if (!weather) {
      this._content.innerHTML = `
        <div class="unavailable">
          Weather entity not available: ${this._config.weather_entity}
        </div>
      `;
      return;
    }

    const temperature = weather.attributes.temperature;
    const temperatureUnit = weather.attributes.temperature_unit || "°C";
    const condition = (conditionSensor && conditionSensor.state !== "unavailable" && conditionSensor.state !== "unknown")
      ? conditionSensor.state
      : "";
    const iconCode = iconCodeSensor ? iconCodeSensor.state : null;

    // Resolve icon from bundled EC icon set, with fallback to icon_path config
    let iconUrl = "";
    if (iconCode && iconCode !== "unknown" && iconCode !== "unavailable") {
      const paddedCode = iconCode.toString().padStart(2, "0");
      iconUrl = EC_ICONS[paddedCode] || `/hacsfiles/environment-canada-weather-card/weather-icons/EnvironmentCanada/${paddedCode}.svg`;
    }

    // Use subscribed forecast, fallback to attribute (older HA)
    const forecast = this._forecast.length > 0
      ? this._forecast
      : (weather.attributes.forecast || []);

    // Build the card HTML
    let html = "";

    // Header: name only
    if (this._config.name) {
      html += `<div class="header"><div class="name">${this._config.name}</div></div>`;
    }

    // Current conditions + alerts side by side
    const alerts = this._getAlerts();
    html += `
      <div class="current">
        <div class="current-icon">
          ${iconUrl ? `<img src="${iconUrl}" alt="${condition}">` : this._getWeatherIcon(weather.state)}
        </div>
        <div class="current-info">
          <div class="current-temp">
            ${Math.round(temperature)}<span class="unit">${temperatureUnit}</span>
          </div>
          <div class="current-condition">${this._toTitleCase(condition)}</div>
        </div>
        ${alerts.length > 0 ? `
          <div class="alerts-container">
            ${alerts.map(a => `
              <div class="alert">
                <div class="alert-text">${a.text}</div>
                <div class="alert-icon"><img src="${a.icon}" alt="${a.text}"></div>
              </div>`).join("")}
          </div>` : ""}
      </div>
    `;

    // Optional attributes (humidity, wind, wind chill, humidex)
    const attrs = weather.attributes;
    const attributeHtml = [];

    if (attrs.humidity !== undefined) {
      attributeHtml.push(`
        <div class="attribute">
          <ha-icon icon="mdi:water-percent"></ha-icon>
          ${attrs.humidity}%
        </div>
      `);
    }

    if (attrs.wind_speed !== undefined) {
      const windUnit = attrs.wind_speed_unit || "km/h";
      attributeHtml.push(`
        <div class="attribute">
          <ha-icon icon="mdi:weather-windy"></ha-icon>
          ${Math.round(attrs.wind_speed)} ${windUnit}
        </div>
      `);
    }

    // Wind chill sensor (only show if not Unknown/unavailable)
    if (this._config.wind_chill_sensor) {
      const windChillSensor = this._hass.states[this._config.wind_chill_sensor];
      if (windChillSensor &&
          windChillSensor.state !== "Unknown" &&
          windChillSensor.state !== "unknown" &&
          windChillSensor.state !== "unavailable") {
        attributeHtml.push(`
          <div class="attribute">
            <ha-icon icon="mdi:snowflake-thermometer"></ha-icon>
            ${Math.round(parseFloat(windChillSensor.state))}° wind chill
          </div>
        `);
      }
    }

    // Humidex sensor (only show if not Unknown/unavailable)
    if (this._config.humidex_sensor) {
      const humidexSensor = this._hass.states[this._config.humidex_sensor];
      if (humidexSensor &&
          humidexSensor.state !== "Unknown" &&
          humidexSensor.state !== "unknown" &&
          humidexSensor.state !== "unavailable") {
        attributeHtml.push(`
          <div class="attribute">
            <ha-icon icon="mdi:sun-thermometer"></ha-icon>
            ${Math.round(parseFloat(humidexSensor.state))}° humidex
          </div>
        `);
      }
    }

    if (attributeHtml.length > 0) {
      html += `<div class="attributes">${attributeHtml.join("")}</div>`;
    }

    // Forecast
    if (this._config.show_forecast && forecast.length > 0) {
      html += `<div class="forecast">`;

      // Show up to 5 days
      const days = this._groupForecastByDay(forecast).slice(0, 5);

      for (const day of days) {
        const weekday = this._getWeekday(day.datetime);
        const forecastCondition = day.condition || "";

        html += `
          <div class="forecast-day">
            <div class="weekday">${weekday}</div>
            <div class="icon">
              ${this._getWeatherIcon(forecastCondition)}
            </div>
            <div class="temp-high">${day.temperature != null ? `${Math.round(day.temperature)}°` : "—"}</div>
            <div class="temp-low">${day.templow != null ? `${Math.round(day.templow)}°` : "—"}</div>
          </div>
        `;
      }

      html += `</div>`;
    }

    this._content.innerHTML = html;
  }

  _groupForecastByDay(forecast) {
    // Group hourly forecasts by day, taking the first entry per day
    // or return daily forecasts as-is
    const days = [];
    const seenDates = new Set();

    for (const entry of forecast) {
      const date = new Date(entry.datetime).toDateString();
      if (!seenDates.has(date)) {
        seenDates.add(date);
        days.push(entry);
      }
    }

    return days;
  }

  _getWeekday(datetime) {
    const date = new Date(datetime);
    const today = new Date();
    const tomorrow = new Date(today);
    tomorrow.setDate(tomorrow.getDate() + 1);

    if (date.toDateString() === today.toDateString()) {
      return "Today";
    } else if (date.toDateString() === tomorrow.toDateString()) {
      return "Tomorrow";
    }

    return date.toLocaleDateString("en-US", { weekday: "long" });
  }

  _getWeatherIcon(condition) {
    // Map weather conditions to Material Design Icons
    const iconMap = {
      "clear-night": "mdi:weather-night",
      "cloudy": "mdi:weather-cloudy",
      "exceptional": "mdi:alert-circle-outline",
      "fog": "mdi:weather-fog",
      "hail": "mdi:weather-hail",
      "lightning": "mdi:weather-lightning",
      "lightning-rainy": "mdi:weather-lightning-rainy",
      "partlycloudy": "mdi:weather-partly-cloudy",
      "pouring": "mdi:weather-pouring",
      "rainy": "mdi:weather-rainy",
      "snowy": "mdi:weather-snowy",
      "snowy-rainy": "mdi:weather-snowy-rainy",
      "sunny": "mdi:weather-sunny",
      "windy": "mdi:weather-windy",
      "windy-variant": "mdi:weather-windy-variant"
    };

    const icon = iconMap[condition] || "mdi:weather-partly-cloudy";
    return `<ha-icon icon="${icon}"></ha-icon>`;
  }

  _getAlerts() {
    if (!this._config.alerts_sensor) return [];
    const sensor = this._hass && this._hass.states[this._config.alerts_sensor];
    if (!sensor || sensor.state === "0" || sensor.state === "unavailable" || sensor.state === "unknown") return [];

    const rawAlerts = sensor.attributes.alerts || [];
    // Priority order: warning > watch > advisory > statement
    const priority = ["warning", "watch", "advisory", "statement"];

    // Collect all alerts sorted by priority, take top 2
    const sorted = [];
    for (const type of priority) {
      for (const a of rawAlerts) {
        if (a.type === type) sorted.push(a);
      }
    }

    return sorted.slice(0, 2).map(alert => {
      const iconKey = alert.color || "statement";
      const icon = ALERT_ICONS[iconKey] || ALERT_ICONS["statement"];
      if (!icon) return null;

      let text;
      if (alert.type === "statement") {
        text = alert.title || "Special Weather Statement";
      } else {
        const colour = alert.color ? this._toTitleCase(alert.color) : "";
        const type = this._toTitleCase(alert.type);
        const subject = (alert.title || "").replace(new RegExp(alert.type, "i"), "").trim();
        text = [colour, type, subject ? `- ${subject}` : ""].filter(Boolean).join(" ");
      }

      return { icon, text };
    }).filter(Boolean);
  }

  _toTitleCase(str) {
    return str.replace(/\S+/g, word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase());
  }

  getCardSize() {
    return 4;
  }
}

// Derives the EC station name from a weather entity ID.
// e.g. "weather.ottawa_kanata_orleans_forecast" → "ottawa_kanata_orleans"
function _stationFromWeatherEntity(entityId) {
  return entityId.replace(/^weather\./, "").replace(/_forecast$/, "");
}

// Visual editor shown in the Lovelace UI card picker / edit dialog
class EnvironmentCanadaWeatherCardEditor extends HTMLElement {
  constructor() {
    super();
    this._config = {};
    this._hass = null;
  }

  set hass(hass) {
    this._hass = hass;
    const form = this.shadowRoot && this.shadowRoot.querySelector("ha-form");
    if (form) form.hass = hass;
  }

  setConfig(config) {
    this._config = { ...config };
    const form = this.shadowRoot && this.shadowRoot.querySelector("ha-form");
    if (form) form.data = this._config;
  }

  connectedCallback() {
    if (!this.shadowRoot) {
      this.attachShadow({ mode: "open" });
    }

    let form = this.shadowRoot.querySelector("ha-form");
    if (!form) {
      form = document.createElement("ha-form");
      form.schema = [
        {
          name: "weather_entity",
          required: true,
          selector: { entity: { domain: "weather" } }
        }
      ];
      form.computeLabel = () => "Weather Entity";
      form.addEventListener("value-changed", (e) => {
        this._config = e.detail.value;
        this.dispatchEvent(new CustomEvent("config-changed", {
          detail: { config: this._config },
          bubbles: true,
          composed: true
        }));
      });
      this.shadowRoot.appendChild(form);
    }

    form.data = this._config;
    if (this._hass) form.hass = this._hass;
  }
}

customElements.define("environment-canada-weather-card-editor", EnvironmentCanadaWeatherCardEditor);

// Register the custom card
customElements.define("environment-canada-weather-card", EnvironmentCanadaWeatherCard);

// Register with Home Assistant's custom card registry
window.customCards = window.customCards || [];
window.customCards.push({
  type: "environment-canada-weather-card",
  name: "Environment Canada Weather Card",
  description: "Weather card using Environment Canada condition text, icon codes, wind chill, and humidex sensors",
  preview: true
});

